// Helper: Validate ID token claims
function validateIdTokenClaims(decoded) {
  if (!decoded || !decoded.payload) {
    throw new Error('Invalid token: unable to decode');
  }

  const payload = decoded.payload;

  // Verify issuer
  if (payload.iss !== OIDC_CONFIG.issuer) {
    throw new Error(`Invalid issuer. Expected: ${OIDC_CONFIG.issuer}, Got: ${payload.iss}`);
  }

  // Verify audience
  const audience = Array.isArray(payload.aud) ? payload.aud : [payload.aud];
  if (!audience.includes(OIDC_CONFIG.clientId)) {
    throw new Error(`Invalid audience. Expected: ${OIDC_CONFIG.clientId}, Got: ${payload.aud}`);
  }

  // Verify expiration
  const now = Math.floor(Date.now() / 1000);
  if (payload.exp && payload.exp < now) {
    throw new Error('Token has expired');
  }

  // Verify issued at (with 5 minute clock skew tolerance)
  if (payload.iat && payload.iat > now + 300) {
    throw new Error('Token issued in the future');
  }

  // Verify sub claim exists
  if (!payload.sub) {
    throw new Error('Token missing sub claim');
  }

  return payload;
}

// Helper: Exchange authorization code for tokens
async function exchangeCodeForTokens(code) {
  const tokenRequestData = new URLSearchParams({
    grant_type: 'authorization_code',
    code: code,
    redirect_uri: OIDC_CONFIG.redirectUri,
    client_id: OIDC_CONFIG.clientId,
    client_secret: OIDC_CONFIG.clientSecret,
  });

  const response = await axios.post(OIDC_CONFIG.tokenEndpoint, tokenRequestData.toString(), {
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
  });

  return response.data;
}

// Helper: Create or update user session from ID token claims
function createUserSession(req, claims, tokens) {
  const user = {
    sub: claims.sub,
    email: claims.email || null,
    name: claims.name || null,
    givenName: claims.given_name || null,
    familyName: claims.family_name || null,
    picture: claims.picture || null,
    emailVerified: claims.email_verified || false,
    authenticatedAt: new Date().toISOString(),
    tokenExpiry: claims.exp ? new Date(claims.exp * 1000).toISOString() : null,
  };

  // Store user in the user store
  userStore.set(claims.sub, {
    ...user,
    accessToken: tokens.access_token,
    refreshToken: tokens.refresh_token || null,
    idToken: tokens.id_token,
    lastLogin: new Date().toISOString(),
  });

  // Set session data
  req.session.user = user;
  req.session.accessToken = tokens.access_token;
  req.session.refreshToken = tokens.refresh_token || null;
  req.session.idToken = tokens.id_token;

  return user;
}

